"""
Parameterized generator for GH300_zulip_33089.

Source PR:    https://github.com/zulip/zulip/pull/33089
Source Issue: N/A

Seed varies: renames 'active' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH300_zulip_33089'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH300_zulip_33089'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('active', 'active' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH300_zulip_33089',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'zulip/zulip',
                "pr_number": 33089,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/zulip/zulip/pull/33089",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'web/src/dropdown_widget.ts': 'import $ from "jquery";\nimport assert from "minimalistic-assert";\nimport * as tippy from "tippy.js";\n\nimport render_dropdown_current_value_not_in_options from "../templates/dropdown_current_value_not_in_options.hbs";\nimport render_dropdown_disabled_state from "../templates/dropdown_disabled_state.hbs";\nimport render_dropdown_list from "../templates/dropdown_list.hbs";\nimport render_dropdown_list_container from "../templates/dropdown_list_container.hbs";\nimport render_inline_decorated_stream_name from "../templates/inline_decorated_stream_name.hbs";\n\nimport * as blueslip from "./blueslip.ts";\nimport * as ListWidget from "./list_widget.ts";\nimport type {ListWidget as ListWidgetType} from "./list_widget.ts";\nimport {page_params} from "./page_params.ts";\nimport * as popover_menus from "./popover_menus.ts";\nimport type {StreamSubscription} from "./sub_store.ts";\nimport {parse_html} from "./ui_util.ts";\nimport * as util from "./util.ts";\n\n/* Sync with max-height set in zulip.css */\nexport const DEFAULT_DROPDOWN_HEIGHT = 210;\nconst noop = (): void => {\n    // Empty function for default values.\n};\n\nexport enum DataTypes {\n    NUMBER = "number",\n    STRING = "string",\n}\n\nexport type Option = {\n    unique_id: number | string;\n    name: string;\n    is_setting_disabled?: boolean;\n    stream?: StreamSubscription;\n};\n\nexport type DropdownWidgetOptions = {\n    widget_name: string;\n    widget_selector?: string;\n    // You can bold the selected `option` by setting `option.bold_current_selection` to `true`.\n    // Currently, not implemented for stream names.\n    get_options: (current_value: string | number | undefined) => Option[];\n    item_click_callback: (\n        event: JQuery.ClickEvent,\n        instance: tippy.Instance,\n        widget: DropdownWidget,\n        is_sticky_bottom_option_clicked: boolean,\n    ) => void;\n    // Provide an parent element to widget which will be re-rendered if the widget is setup again.\n    // It is important to not pass `$("body")` here for widgets that would be `setup()`\n    // multiple times, so that we don\'t have duplicate event handlers.\n    $events_container: JQuery;\n    on_show_callback?: (instance: tippy.Instance, widget: DropdownWidget) => void;\n    on_mount_callback?: (instance: tippy.Instance) => void;\n    on_hidden_callback?: (instance: tippy.Instance) => void;\n    on_exit_with_escape_callback?: () => void;\n    render_selected_option?: () => void;\n    // Used to add a sticky button at the bottom of the dropdown.\n    sticky_bottom_option?: string;\n    // Used to focus the `target` after dropdown is closed. This is important since the dropdown is\n    // appended to `body` and hence `body` is focused when the dropdown is closed, which makes\n    // it hard for the user to get focus back to the `target`.\n    focus_target_on_hidden?: boolean;\n    tippy_props?: Partial<tippy.Props>;\n    // NOTE: Any value other than `undefined` will be rendered when class is initialized.\n    default_id?: string | number | undefined;\n    unique_id_type?: DataTypes;\n    // Text to show if the current value is not in `get_options()`.\n    text_if_current_value_not_in_options?: string;\n    hide_search_box?: boolean;\n    // Disable the widget for spectators.\n    disable_for_spectators?: boolean;\n    dropdown_input_visible_selector?: string;\n    prefer_top_start_placement?: boolean;\n};\n\nexport class DropdownWidget {\n    widget_name: string;\n    widget_selector: string;\n    widget_wrapper_id: string;\n    widget_value_selector: string;\n    get_options: (current_value: string | number | undefined) => Option[];\n    item_click_callback: (\n        event: JQuery.ClickEvent,\n        instance: tippy.Instance,\n        widget: DropdownWidget,\n        is_sticky_bottom_option_clicked: boolean,\n    ) => void;\n    focus_target_on_hidden: boolean;\n    on_show_callback: (instance: tippy.Instance, widget: DropdownWidget) => void;\n    on_mount_callback: (instance: tippy.Instance) => void;\n    on_hidden_callback: (instance: tippy.Instance) => void;\n    on_exit_with_escape_callback: () => void;\n    render_selected_option: () => void;\n    sticky_bottom_option: string | undefined;\n    tippy_props: Partial<tippy.Props>;\n    list_widget: ListWidgetType<Option, Option> | undefined;\n    instance: tippy.Instance | undefined;\n    default_id: string | number | undefined;\n    current_value: string | number | undefined;\n    unique_id_type: DataTypes | undefined;\n    $events_container: JQuery;\n    text_if_current_value_not_in_options: string;\n    hide_search_box: boolean;\n    disable_for_spectators: boolean;\n    dropdown_input_visible_selector: string;\n    prefer_top_start_placement: boolean;\n\n    // TODO: This is only used in one widget, with no implementation\n    // here, so should be generalized or reworked.\n    item_clicked = false;\n\n    constructor(options: DropdownWidgetOptions) {\n        this.widget_name = options.widget_name;\n        this.widget_selector = options.widget_selector ?? `#${CSS.escape(this.widget_name)}_widget`;\n        // A widget wrapper may not exist based on the UI requirement.\n        this.widget_wrapper_id = `${this.widget_selector}_wrapper`;\n        this.widget_value_selector = `${this.widget_selector} .dropdown_widget_value`;\n        this.get_options = options.get_options;\n        this.item_click_callback = options.item_click_callback;\n        this.focus_target_on_hidden = options.focus_target_on_hidden ?? true;\n        this.on_show_callback = options.on_show_callback ?? noop;\n        this.on_mount_callback = options.on_mount_callback ?? noop;\n        this.on_hidden_callback = options.on_hidden_callback ?? noop;\n        this.on_exit_with_escape_callback = options.on_exit_with_escape_callback ?? noop;\n        this.render_selected_option = options.render_selected_option ?? noop;\n        this.sticky_bottom_option = options.sticky_bottom_option;\n        // These properties can override any tippy props.\n        this.tippy_props = options.tippy_props ?? {};\n        this.list_widget = undefined;\n        this.default_id = options.default_id;\n        this.current_value = this.default_id;\n        this.unique_id_type = options.unique_id_type;\n        this.$events_container = options.$events_container;\n        this.text_if_current_value_not_in_options =\n            options.text_if_current_value_not_in_options ?? "";\n        this.hide_search_box = options.hide_search_box ?? false;\n        this.disable_for_spectators = options.disable_for_spectators ?? false;\n        this.dropdown_input_visible_selector =\n            options.dropdown_input_visible_selector ?? this.widget_selector;\n        this.prefer_top_start_placement = options.prefer_top_start_placement ?? false;\n    }\n\n    init(): void {\n        // NOTE: Widget should only be initialized again if the events_container was rendered again to\n        // avoid duplicate events to be attached to events_container.\n        // Don\'t attach any events or classes to any element other than `events_container` here, otherwise\n        // the attached events / classes will be lost when the widget is rendered again without initialing the widget again.\n        if (this.current_value !== undefined) {\n            this.render();\n        }\n\n        this.$events_container.on(\n            "keydown",\n            `${this.widget_selector}, ${this.widget_wrapper_id}`,\n            (e) => {\n                if (e.key === "Enter") {\n                    $(this.widget_selector)[0]?.click();\n                    e.stopPropagation();\n                    e.preventDefault();\n                }\n            },\n        );\n\n        if (this.disable_for_spectators && page_params.is_spectator) {\n            this.$events_container.addClass("dropdown-widget-disabled-for-spectators");\n            this.$events_container.on(\n                "click",\n                `${this.widget_selector}, ${this.widget_wrapper_id}`,\n                (e) => {\n                    e.stopPropagation();\n                    e.preventDefault();\n                },\n            );\n        }\n    }\n\n    adjust_dropdown_position_post_list_render(tippy_instance: tippy.Instance): void {\n        let top_offset = 0;\n        let left_offset = 0;\n\n        // Use offset if provided by the widget callers.\n        if (typeof this.tippy_props?.offset === "object" && this.tippy_props?.offset.length === 2) {\n            left_offset = this.tippy_props.offset[0];\n            top_offset = this.tippy_props.offset[1];\n        }\n\n        const window_height = window.innerHeight;\n        let dropdown_search_box_and_padding_height = 50;\n        if (this.hide_search_box) {\n            dropdown_search_box_and_padding_height = 0;\n        }\n        const dropdown_input_props = $(this.dropdown_input_visible_selector).get_offset_to_window();\n        const dropdown_input_top = dropdown_input_props.top;\n\n        // Pixels above the dropdown input.\n        const top_space = dropdown_input_top - top_offset - dropdown_search_box_and_padding_height;\n        // Pixels below the top of dropdown input.\n        const bottom_space =\n            window_height - dropdown_input_top - dropdown_search_box_and_padding_height;\n\n        // Show dropdown at bottom by default if we `DEFAULT_DROPDOWN_HEIGHT`\n        // space available unless the dropdown caller prefers to show at top.\n        // If we don\'t have `DEFAULT_DROPDOWN_HEIGHT` space available above\n        // or below the dropdown input, show the dropdown at maximum space.\n        let placement: tippy.Placement = "top-start";\n        let height: number = Math.min(DEFAULT_DROPDOWN_HEIGHT, Math.max(top_space, bottom_space));\n        if (this.prefer_top_start_placement && top_space > DEFAULT_DROPDOWN_HEIGHT) {\n            height = DEFAULT_DROPDOWN_HEIGHT;\n        } else if (!this.prefer_top_start_placement && bottom_space > DEFAULT_DROPDOWN_HEIGHT) {\n            placement = "bottom-start";\n            height = DEFAULT_DROPDOWN_HEIGHT;\n            // Use the provided offset if we have enough space. Otherwise,\n            // we overlap the top of dropdown with top of dropdown input.\n            if (this.tippy_props?.offset === undefined) {\n                top_offset = -1 * dropdown_input_props.height;\n            }\n        } else if (bottom_space > top_space) {\n            placement = "bottom-start";\n            top_offset = -1 * dropdown_input_props.height;\n        }\n\n        const offset: [number, number] = [left_offset, top_offset];\n        tippy_instance.setProps({placement, offset});\n        const $popper = $(tippy_instance.popper);\n        $popper.find(".dropdown-list-wrapper").css("max-height", height + "px");\n    }\n\n    show_empty_if_no_items($popper: JQuery): void {\n        assert(this.list_widget !== undefined);\n        const list_items = this.list_widget.get_current_list();\n        const $no_search_results = $popper.find(".no-dropdown-items");\n        if (list_items.length === 0) {\n            $no_search_results.show();\n        } else {\n            $no_search_results.hide();\n        }\n    }\n\n    setup(): void {\n        this.init();\n        const delegate_container = util.the(this.$events_container);\n\n        if (this.disable_for_spectators && page_params.is_spectator) {\n            return;\n        }\n\n        tippy.delegate(delegate_container, {\n            ...popover_menus.default_popover_props,\n            target: this.widget_selector,\n            // Custom theme defined in popovers.css\n            theme: "dropdown-widget",\n            arrow: false,\n            onShow: (instance: tippy.Instance) => {\n                if (util.is_mobile()) {\n                    // The dropdown trigger button can be hidden by the\n                    // keyboard on mobile or if it is scrolled out of\n                    // view to keyboard being displayed.\n                    // So, we show the dropdown even if reference is hidden on\n                    // mobile.\n                    $(instance.popper).find(".tippy-box").addClass("show-when-reference-hidden");\n                }\n                instance.setContent(\n                    parse_html(\n                        render_dropdown_list_container({\n                            widget_name: this.widget_name,\n                            hide_search_box: this.hide_search_box,\n                            sticky_bottom_option: this.sticky_bottom_option,\n                        }),\n                    ),\n                );\n                const $popper = $(instance.popper);\n                const $dropdown_list_body = $popper.find(".dropdown-list");\n                const $search_input = $popper.find<HTMLInputElement>(\n                    "input.dropdown-list-search-input",\n                );\n\n                this.list_widget = ListWidget.create(\n                    $dropdown_list_body,\n                    this.get_options(this.current_value),\n                    {\n                        name: `${CSS.escape(this.widget_name)}-list-widget`,\n                        get_item: ListWidget.default_get_item,\n                        modifier_html(item) {\n                            return render_dropdown_list({item});\n                        },\n                        filter: {\n                            $element: $search_input,\n                            predicate(item, value) {\n                                return item.name.toLowerCase().includes(value);\n                            },\n                        },\n                        $simplebar_container: $popper.find(".dropdown-list-wrapper"),\n                    },\n                );\n\n                $search_input.on("input.list_widget_filter", () => {\n                    this.show_empty_if_no_items($popper);\n                });\n\n                // Keyboard handler\n                $popper.on("keydown", (e) => {\n                    function trigger_element_focus($element: JQuery): void {\n                        e.preventDefault();\n                        e.stopPropagation();\n                        // When bringing a non-visible element into view, scroll as minimum as possible.\n                        $element[0]?.scrollIntoView({block: "nearest"});\n                        $element.trigger("focus");\n                    }\n\n                    const $search_input = $popper.find(".dropdown-list-search-input");\n                    const $sticky_bottom_option = $popper.find(".sticky-bottom-option");\n                    assert(this.list_widget !== undefined);\n                    const list_items = this.list_widget.get_current_list();\n                    if (\n                        list_items.length === 0 &&\n                        !(e.key === "Escape") &&\n                        !this.sticky_bottom_option\n                    ) {\n                        // Let the browser handle it.\n                        return;\n                    }\n\n                    function first_item(): JQuery {\n                        const first_item = list_items[0];\n                        assert(first_item !== undefined);\n                        return $popper.find(`.list-item[data-unique-id="${first_item.unique_id}"]`);\n                    }\n\n                    function last_item(): JQuery {\n                        const last_item = list_items.at(-1);\n                        assert(last_item !== undefined);\n                        return $popper.find(`.list-item[data-unique-id="${last_item.unique_id}"]`);\n                    }\n\n                    const render_all_items_and_focus_last_item = (): void => {\n                        assert(this.list_widget !== undefined);\n                        // List widget doesn\'t render all items by default, so we need to render all\n                        // the items and focus on the last element.\n                        const list_items = this.list_widget.get_current_list();\n                        this.list_widget.render(list_items.length);\n                        trigger_element_focus(last_item());\n                    };\n\n                    const handle_arrow_down_on_last_item = (): void => {\n                        if (this.sticky_bottom_option) {\n                            trigger_element_focus($sticky_bottom_option);\n                        } else if (this.hide_search_box) {\n                            trigger_element_focus(first_item());\n                        } else {\n                            trigger_element_focus($search_input);\n                        }\n                    };\n\n                    const handle_arrow_down_on_sticky_bottom_option = (): void => {\n                        if (this.hide_search_box) {\n                            trigger_element_focus(first_item());\n                        } else {\n                            trigger_element_focus($search_input);\n                        }\n                    };\n\n                    const handle_arrow_up_on_sticky_bottom_option = (): void => {\n                        if (list_items.length > 0) {\n                            render_all_items_and_focus_last_item();\n                        } else if (!this.hide_search_box) {\n                            trigger_element_focus($search_input);\n                        }\n                    };\n\n                    const handle_arrow_down_on_search_input = (): void => {\n                        if (list_items.length > 0) {\n                            trigger_element_focus(first_item());\n                        } else if (this.sticky_bottom_option) {\n                            trigger_element_focus($sticky_bottom_option);\n                        }\n                    };\n\n                    const handle_arrow_up_on_search_input = (): void => {\n                        if (this.sticky_bottom_option) {\n                            trigger_element_focus($sticky_bottom_option);\n                        } else {\n                            render_all_items_and_focus_last_item();\n                        }\n                    };\n\n                    const handle_arrow_up_on_first_item = (): void => {\n                        if (this.hide_search_box) {\n                            render_all_items_and_focus_last_item();\n                        } else {\n                            trigger_element_focus($search_input);\n                        }\n                    };\n\n                    switch (e.key) {\n                        case "Enter":\n                            if (\n                                list_items.length === 0 ||\n                                e.target === $sticky_bottom_option.get(0)\n                            ) {\n                                $sticky_bottom_option.trigger("click");\n                            } else if (e.target === $search_input.get(0)) {\n                                // Select first item if in search input.\n                                first_item().trigger("click");\n                            } else if (list_items.length > 0) {\n                                $(e.target).trigger("click");\n                            }\n                            e.stopPropagation();\n                            e.preventDefault();\n                            break;\n\n                        case "Escape":\n                            popover_menus.hide_current_popover_if_visible(instance);\n                            this.on_exit_with_escape_callback();\n                            e.stopPropagation();\n                            e.preventDefault();\n                            break;\n\n                        case "Tab":\n                        case "ArrowDown":\n                            switch (e.target) {\n                                case $search_input.get(0):\n                                    handle_arrow_down_on_search_input();\n                                    break;\n                                case $sticky_bottom_option.get(0):\n                                    handle_arrow_down_on_sticky_bottom_option();\n                                    break;\n                                case last_item().get(0):\n                                    handle_arrow_down_on_last_item();\n                                    break;\n                                default:\n                                    trigger_element_focus($(e.target).next());\n                            }\n                            break;\n\n                        case "ArrowUp":\n                            switch (e.target) {\n                                case $search_input.get(0):\n                                    handle_arrow_up_on_search_input();\n                                    break;\n                                case $sticky_bottom_option.get(0):\n                                    handle_arrow_up_on_sticky_bottom_option();\n                                    break;\n                                case first_item().get(0):\n                                    handle_arrow_up_on_first_item();\n                                    break;\n                                default:\n                                    trigger_element_focus($(e.target).prev());\n                            }\n                            break;\n                    }\n                });\n\n                // Click on item.\n                $popper.on("click", ".list-item", (event) => {\n                    const selected_unique_id = $(event.currentTarget).attr("data-unique-id");\n                    assert(selected_unique_id !== undefined);\n                    this.current_value = selected_unique_id;\n                    if (this.unique_id_type === DataTypes.NUMBER) {\n                        this.current_value = Number.parseInt(this.current_value, 10);\n                    }\n                    this.item_click_callback(event, instance, this, false);\n                });\n\n                // Click on $sticky_bottom_option.\n                $popper.on("click", ".sticky-bottom-option", (event) => {\n                    this.item_click_callback(event, instance, this, true);\n                });\n\n                // Set focus on first element when dropdown opens.\n                setTimeout(() => {\n                    if (this.hide_search_box) {\n                        $dropdown_list_body.find(".list-item:first-child").trigger("focus");\n                    } else {\n                        $search_input.trigger("focus");\n                    }\n                }, 0);\n\n                this.on_show_callback(instance, this);\n                this.adjust_dropdown_position_post_list_render(instance);\n            },\n            onMount: (instance: tippy.Instance) => {\n                this.show_empty_if_no_items($(instance.popper));\n                this.on_mount_callback(instance);\n            },\n            onHidden: (instance: tippy.Instance) => {\n                if (this.focus_target_on_hidden) {\n                    $(this.widget_selector).trigger("focus");\n                }\n                this.on_hidden_callback(instance);\n                instance.destroy();\n            },\n            ...this.tippy_props,\n        });\n    }\n\n    value(): number | string | undefined {\n        return this.current_value;\n    }\n\n    // NOTE: This function needs to be explicitly called when you want to update the\n    // current value of the widget. We don\'t call this automatically since some of our\n    // dropdowns don\'t need it. Maybe we can follow a reverse approach in the future.\n    render(value?: number | string): void {\n        // Check if the value is valid otherwise just render previous value.\n        if (value !== undefined && typeof value === typeof this.current_value) {\n            this.current_value = value;\n        }\n\n        const all_options = this.get_options(this.current_value);\n        const option = all_options.find((option) => option.unique_id === this.current_value);\n\n        // If provided, show custom text if cannot find current option.\n        if (!option && this.text_if_current_value_not_in_options) {\n            $(this.widget_value_selector).html(\n                render_dropdown_current_value_not_in_options({\n                    name: this.text_if_current_value_not_in_options,\n                }),\n            );\n            return;\n        }\n\n        if (!option) {\n            blueslip.error(`Cannot find current value: ${this.current_value} in provided options.`);\n            return;\n        }\n\n        if (option.is_setting_disabled) {\n            $(this.widget_value_selector).html(render_dropdown_disabled_state({name: option.name}));\n        } else if (option.stream) {\n            $(this.widget_value_selector).html(\n                render_inline_decorated_stream_name({\n                    stream: option.stream,\n                    show_colored_icon: true,\n                }),\n            );\n        } else {\n            $(this.widget_value_selector).text(option.name);\n        }\n    }\n}\n',
            'web/styles/zulip.css': 'html {\n    overflow: hidden scroll;\n    overscroll-behavior-y: none;\n    width: calc(100% - var(--disabled-scrollbar-width));\n}\n\nbody,\nhtml {\n    height: 100%;\n    touch-action: manipulation;\n}\n\n.column-middle,\n#main_div {\n    background-color: var(--color-background);\n}\n\n#app-loading.loaded {\n    display: none !important; /* We are now loaded, by definition. */\n}\n\nbody {\n    width: 100%;\n    margin: 0;\n    padding: 0;\n    font-size: var(--base-font-size-px);\n    /* The line-height used in most of the UI should be at least\n       its legacy value, but should expand with larger base\n       line-height values. */\n    line-height: max(\n        var(--legacy-body-line-height-unitless),\n        var(--base-line-height-unitless)\n    );\n    font-family: "Source Sans 3 VF", sans-serif;\n    color: var(--color-text-default);\n    background-color: var(--color-background);\n\n    /* Implementation for fluid layout width setting. */\n    .header-main,\n    .app .app-main,\n    #compose-container {\n        max-width: calc(\n            var(--left-sidebar-max-width) + var(--message-area-max-width) +\n                var(--right-sidebar-max-width)\n        );\n    }\n\n    /* When sidebars are manually hidden, we set the max-width\n       for the layout to a different maximum width. This keeps\n       the message area predictably readable. */\n    &.hide-left-sidebar:not(.fluid_layout_width) {\n        .header-main,\n        .app .app-main,\n        #compose-container {\n            max-width: calc(\n                var(--message-area-max-width) + var(--right-sidebar-max-width)\n            );\n\n            /* When we\'re less than the xl_min breakpoint, we instead\n               constrain to just the message area\'s max-width, since\n               the right column will be hidden below that point. */\n            @container header-container (width < $cq_xl_min) {\n                max-width: var(--message-area-max-width);\n            }\n\n            @container app (width < $cq_xl_min) {\n                max-width: var(--message-area-max-width);\n            }\n        }\n    }\n\n    /* Fallback media query. */\n    @media (width < $xl_min) {\n        &.without-container-query-support.hide-left-sidebar:not(\n                .fluid_layout_width\n            ) {\n            .header-main,\n            .app .app-main,\n            #compose-container {\n                max-width: var(--message-area-max-width);\n            }\n        }\n    }\n\n    &.hide-right-sidebar:not(.fluid_layout_width) {\n        .header-main,\n        .app .app-main,\n        #compose-container {\n            max-width: calc(\n                var(--left-sidebar-max-width) + var(--message-area-max-width)\n            );\n        }\n    }\n\n    &.hide-left-sidebar.hide-right-sidebar:not(.fluid_layout_width) {\n        .header-main,\n        .app .app-main,\n        #compose-container {\n            max-width: var(--message-area-max-width);\n        }\n    }\n\n    &.fluid_layout_width {\n        .header-main,\n        .app .app-main,\n        #compose-container {\n            max-width: inherit;\n        }\n    }\n}\n\ninput,\nbutton,\nselect,\ntextarea {\n    font-family: "Source Sans 3 VF", sans-serif;\n    /* Disable bootstrap size CSS; we want to use our default font size on\n       body for input elements. */\n    line-height: normal;\n    font-size: inherit;\n}\n\nblockquote p {\n    font-weight: normal;\n}\n\n/* These colors are typically overridden,\n   but referencing them as variables prevents\n   specificity wars and ugly :not() selectors,\n   especially in dark theme. */\na {\n    cursor: pointer;\n    color: var(--color-text-generic-link);\n    text-decoration: none;\n}\n\na:hover,\na:focus {\n    color: var(--color-text-generic-link-interactive);\n    text-decoration: underline;\n\n    & code {\n        color: var(--color-text-generic-link-interactive);\n    }\n}\n\ncode,\npre {\n    font-family: "Source Code Pro", monospace;\n}\n\n.no-select {\n    user-select: none;\n}\n\n.text-select {\n    user-select: text;\n}\n\np.n-margin {\n    margin: 10px 0 0;\n}\n\n.small-line-height {\n    line-height: 1.1;\n}\n\n.float-left {\n    float: left;\n}\n\n.float-right {\n    float: right;\n}\n\n.float-clear {\n    clear: both;\n}\n\n.no-margin {\n    margin: 0;\n}\n\n.history-limited-box {\n    color: hsl(16deg 60% 45%);\n    border: 1px solid hsl(16deg 60% 45%);\n    box-shadow: 0 0 2px hsl(16deg 60% 45%);\n}\n\n.all-messages-search-caution {\n    border: 1px solid hsl(192deg 19% 75% / 20%);\n    box-shadow: 0 0 2px hsl(192deg 19% 75% / 20%);\n}\n\n.history-limited-box,\n.all-messages-search-caution {\n    border-radius: 4px;\n    display: none;\n    margin: 0 auto 12px;\n    padding: 5px;\n    /* Difference should be 16px to accommodate the icon. */\n    /* This emulates hanging indent. */\n    padding-left: 26px;\n    text-indent: -10px;\n\n    .all-messages-search-caution-icon {\n        margin: 0 3px 0 1px;\n    }\n\n    & p {\n        margin: 0;\n        padding: 4px;\n    }\n}\n\n.bottom-messages-logo {\n    display: none;\n}\n\n.alert-zulip-logo,\n.top-messages-logo,\n.bottom-messages-logo {\n    width: 24px;\n    height: 24px;\n    margin: 0 auto 12px;\n\n    & svg {\n        & circle {\n            fill: var(--color-zulip-logo);\n            stroke: var(--color-zulip-logo);\n        }\n\n        & path {\n            fill: var(--color-zulip-logo-z);\n            stroke: var(--color-zulip-logo-z);\n        }\n    }\n\n    &.loading circle {\n        fill: var(--color-zulip-logo-loading);\n        stroke: var(--color-zulip-logo-loading);\n    }\n}\n\n.top-messages-logo {\n    /* Since padding under message header is not transparent\n       we need to position it below the padding. */\n    padding-top: var(--header-padding-bottom);\n    margin-bottom: 0;\n    /* To fit the logo inside the spinner. */\n    position: relative;\n    top: -2px;\n}\n\n/* See https://web.dev/animations-guide/#triggers before adding any funny animation properties here. */\n@keyframes feedback-slide-in {\n    from {\n        transform: translateY(-120%);\n        opacity: 0;\n    }\n\n    to {\n        transform: translateY(50px);\n        opacity: 1;\n    }\n}\n\n@keyframes feedback-slide-out {\n    from {\n        transform: translateY(50px);\n        opacity: 1;\n    }\n\n    to {\n        transform: translateY(-120%);\n        opacity: 0;\n    }\n}\n\n#feedback_container {\n    display: none;\n    position: fixed;\n    width: 400px;\n    top: 0;\n    left: calc(50vw - 220px);\n    padding: 15px;\n    background-color: var(--color-background-modal);\n    border-radius: 5px;\n    box-shadow: 0 0 30px hsl(0deg 0% 0% / 25%);\n    z-index: 110;\n\n    @container app (width < $cq_md_min) {\n        width: calc(90% - 30px);\n        left: 5%;\n        top: 5%;\n    }\n\n    &.show-feedback-container {\n        display: block;\n        animation: feedback-slide-in 0.6s forwards;\n    }\n\n    &.slide-out-feedback-container {\n        animation: feedback-slide-out 0.6s;\n    }\n\n    & h3 {\n        font-size: 16pt;\n        margin-top: 2px;\n    }\n\n    .exit-me {\n        font-size: 20pt;\n        font-weight: 200;\n        margin: 0 0 0 10px;\n        cursor: pointer;\n    }\n}\n\n#navbar-fixed-container {\n    position: fixed;\n    top: 0;\n    z-index: 102;\n}\n\n/* Adjust width of any fixed / absolute positioned elements that might be visible in\n   the background when a overlay / modal is open. */\n#navbar-fixed-container,\n#compose {\n    width: calc(100% - var(--disabled-scrollbar-width));\n}\n\n.header {\n    width: 100%;\n    height: var(--header-height);\n    /* Since the headers are sticky, we need non-transparent background. */\n    background-color: var(--color-background);\n    /* Add 1px box-shadow below header so that if there is a gap between sticky header\n       and header at some zoom level, it is covered by this */\n    box-shadow: 0 1px 0 0 var(--color-background);\n}\n\n#navbar-middle .column-middle-inner,\n.header,\n#message_view_header {\n    background-color: var(--color-background-navbar);\n    box-shadow: inset 0 -1px 0 var(--color-navbar-bottom-border);\n}\n\n.app {\n    min-width: 100%;\n    min-height: 100%;\n    z-index: 99;\n}\n\n.app-main,\n.header-main {\n    width: 100%;\n    margin: 0 auto;\n    padding: 0;\n    position: relative;\n}\n\nbody.has-overlay-scrollbar {\n    /* Move simplebar scrollbar to the left so that\n       browser scrollbar doesn\'t overlap with it. */\n    .app-main .column-right .simplebar-track.simplebar-vertical {\n        right: var(--browser-overlay-scrollbar-width);\n    }\n}\n\n/* Styles for popovers rendered as an overlay at the\n   center of the screen, primarily used in mobile sizes. */\n#popover-overlay-background {\n    position: fixed;\n    inset: 0;\n\n    /* Needs to be higher than the 105 for div.overlay so that the\n       emoji picker can render on top of the user status picker. */\n    z-index: 106;\n    background-color: hsl(0deg 0% 0% / 70%);\n}\n\n.white-space-preserve-wrap {\n    white-space: pre-wrap;\n}\n\n.white-space-preserve {\n    white-space: pre;\n}\n\n.white-space-nowrap {\n    white-space: nowrap;\n}\n\n/* Set flex display on login buttons only in the\n   spectator view. We want them to display none\n   otherwise. */\n.spectator-view #top_navbar .column-right .spectator_login_buttons {\n    display: flex;\n}\n\n/* This applies to column-left both in navbar and app. */\n.column-right {\n    width: var(--right-sidebar-width);\n    max-width: var(--right-sidebar-max-width);\n    position: absolute;\n    right: 0;\n    top: 0;\n\n    .spectator_login_buttons {\n        /* Allow the login buttons flexbox to\n           grow and shrink to fit the available\n           area. */\n        flex: 1 1 0;\n        /* Use a flexbox gap of 7px between the\n           buttons to reflect the outer 7px of space. */\n        gap: 7px;\n        /* Don\'t allow login buttons flexbox to\n           break out of the allotted right-column\n           space. */\n        overflow: hidden;\n        /* This should be removed once the navbar\n           has been rewritten entirely with modern\n           layout methods. For now, we pull this up\n           so that the buttons and search box are\n           the same height and their boxes sit on the\n           same invisible line. */\n        margin-top: -1px;\n        /* Prevent collisions with the search box. */\n        margin-left: 15px;\n\n        & a {\n            font-size: calc(16em / 14);\n            /* Vertically size the buttons to\n               match the search box. */\n            line-height: 28px;\n            font-weight: 450;\n            letter-spacing: 0.03ch;\n            /* Allow individual buttons to grow\n               and shrink inside their containers,\n               with padding to prevent text from\n               sitting against the edge of the button. */\n            flex: 1 1 0;\n            padding: 0 4px;\n            /* Center the text nodes within the\n               flex items. */\n            text-align: center;\n            /* Internationalization: disallow wrapping,\n               and display an ellipsis when there\'s not\n               space enough to accommodate the button\n               text. */\n            white-space: nowrap;\n            overflow: hidden;\n            text-overflow: ellipsis;\n            /* Button curvature and transitions. */\n            border-radius: 4px;\n            transition: transform 100ms ease-out;\n\n            &:hover,\n            &:focus {\n                text-decoration: none;\n            }\n\n            &:active {\n                transform: scale(0.98);\n            }\n\n            & i {\n                margin-right: 3px;\n            }\n        }\n\n        & .login_button {\n            color: var(\n                --color-navbar-spectator-medium-attention-brand-button-text\n            );\n            background-color: var(\n                --color-navbar-spectator-medium-attention-brand-button-background\n            );\n\n            &:hover,\n            &:focus {\n                color: var(\n                    --color-navbar-spectator-medium-attention-brand-button-text\n                );\n                background-color: var(\n                    --color-navbar-spectator-medium-attention-brand-button-background-hover\n                );\n            }\n\n            &:active {\n                color: var(\n                    --color-navbar-spectator-medium-attention-brand-button-text\n                );\n                background-color: var(\n                    --color-navbar-spectator-medium-attention-brand-button-background-active\n                );\n            }\n        }\n    }\n\n    .spectator_narrow_login_button {\n        position: absolute;\n        top: 0;\n        right: 0;\n        height: var(--header-height);\n        width: var(--header-height);\n\n        @media (width >= $xl_min) and (height >= 600px) {\n            display: none;\n        }\n\n        .login_button {\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            height: 100%;\n\n            &:hover {\n                text-decoration: none;\n            }\n\n            & i {\n                color: var(--color-navbar-icon);\n                font-size: 1.6em;\n            }\n        }\n    }\n}\n\n/* This applies to column-left both in navbar and app. */\n.column-left {\n    width: var(--left-sidebar-width);\n    max-width: var(--left-sidebar-width);\n    position: absolute;\n    left: 0;\n    top: 0;\n}\n\n.app-main .column-right.expanded,\n.app-main .column-left.expanded {\n    /* We share a baseline z-index to make\n       sure overlays respect the .topmost-overlay\n       below. */\n    z-index: 10;\n}\n\n.app-main .column-right.expanded.topmost-overlay,\n.app-main .column-left.expanded.topmost-overlay {\n    z-index: 15;\n}\n\n#message_feed_container,\n.app-main .column-left .left-sidebar,\n.app-main .column-right .right-sidebar {\n    padding-top: calc(\n        var(--navbar-fixed-height) + var(--header-padding-bottom)\n    );\n}\n\n.app-main {\n    height: 100%;\n    min-height: 100%;\n\n    &::after {\n        /* We use `content` values to determine\n           viewport state from JavaScript; this\n           hides the values without disrupting\n           the document flow. */\n        position: absolute;\n        display: none;\n    }\n\n    .column-left .left-sidebar,\n    .column-right .right-sidebar {\n        position: fixed;\n        z-index: 100;\n    }\n\n    .column-left .left-sidebar {\n        width: var(--left-sidebar-width);\n        padding-left: var(--left-sidebar-padding-left);\n    }\n\n    .column-right .right-sidebar {\n        padding-left: var(--right-sidebar-left-spacing);\n        width: var(--right-sidebar-width);\n    }\n\n    .column-middle {\n        min-height: 100%;\n        /* We need `overflow-y: visible` for sticky headers to work. */\n    }\n}\n\n/* We test for spec-aligned container query support\n   using these styles. */\n.container-query-test {\n    /* Keep the test div from rendering. */\n    visibility: hidden;\n    /* Establish a container. */\n    container: test-container / inline-size;\n    /* Establish a positioning context that\n       conforming browsers will ignore. */\n    position: relative;\n    top: 100px;\n\n    .container-query-test-child {\n        /* Non-spec aligned browsers will keep\n           this element to the top of the containing\n           <div>; spec-aligned browsers move it to the\n           top of the viewport. We check for this in\n           information_density.ts */\n        position: fixed;\n        top: 0;\n    }\n}\n\n.with-container-query-support {\n    /* With spec-aligned container support, we\n       can establish em-aware containers to\n       query as needed.\n       Note that container queries can only\n       act on children of the container, so\n       at least for now, we include separate\n       queries for #header-container in the\n       navbar as well as .app-main in capable\n       browsers.\n    */\n    #header-container {\n        container: header-container / inline-size;\n    }\n\n    .app {\n        container: app / inline-size;\n    }\n}\n\n.column-middle,\n#compose-content {\n    margin-right: var(--right-sidebar-width);\n    margin-left: calc(\n        var(--left-sidebar-width) + var(--left-sidebar-padding-left)\n    );\n    position: relative;\n}\n\ntextarea,\ninput {\n    font-family: "Source Sans 3 VF", sans-serif;\n}\n\n/* Override Bootstrap\'s fixed sizes for various elements */\ntextarea,\nlabel {\n    font-size: inherit;\n    line-height: inherit;\n}\n\n/* Bootstrap\'s focus outline uses -webkit-focus-ring-color which doesn\'t exist in Firefox */\na:not(:active):focus,\nbutton:focus,\nlabel.checkbox input[type="checkbox"]:focus ~ .rendered-checkbox,\ni.fa:focus,\ni.zulip-icon:focus-visible,\n[role="button"]:focus {\n    outline: 2px solid var(--color-outline-focus);\n    /* TODO: change solid to auto once the Chromium bug #1105822 is fixed */\n}\n\n/* List of text-like input types taken from Bootstrap */\ninput {\n    &[type="text"],\n    &[type="password"],\n    &[type="datetime"],\n    &[type="datetime-local"],\n    &[type="date"],\n    &[type="month"],\n    &[type="time"],\n    &[type="week"],\n    &[type="number"],\n    &[type="email"],\n    &[type="url"],\n    &[type="search"],\n    &[type="tel"],\n    &[type="color"] {\n        font-size: inherit;\n        height: 1.4em;\n    }\n}\n\nli,\n.table th,\n.table td {\n    line-height: inherit;\n}\n\n.bootstrap-btn {\n    font-size: inherit;\n    height: auto;\n    line-height: 100%;\n}\n\n/* Classes which style copy buttons */\n.copy_button_base {\n    outline-color: hsl(0deg 0% 73%);\n    height: 18px;\n    width: 10px;\n    padding: 6px;\n    display: block;\n    /* The below two avoids the padded element from displaying\n    its own border and background color */\n    border: none;\n    background-clip: content-box;\n\n    &:hover svg path {\n        fill: var(--color-fill-hover-copy-icon);\n    }\n}\n\n.copy_message {\n    position: absolute;\n    top: 5px;\n    right: 5px;\n    height: 1em;\n    backdrop-filter: blur(20px);\n    outline: 1px solid var(--color-copy-button-square-bg-active);\n}\n\n#copy_generated_link_container {\n    display: flex;\n    gap: 4px;\n    align-items: center;\n}\n\n#copy_generated_invite_link {\n    position: relative;\n    right: -30px;\n}\n\n/* Classes for hiding and showing controls */\n\n.notdisplayed {\n    display: none !important;\n}\n\n.notvisible {\n    visibility: hidden !important;\n    width: 0 !important;\n    min-width: 0 !important;\n    min-height: 0 !important;\n    height: 0 !important;\n    overflow: hidden !important;\n    position: absolute !important;\n}\n\n/* Lighter strong */\n\nstrong {\n    font-weight: 600;\n}\n\n.preserve_spaces {\n    white-space: pre-wrap;\n}\n\n.logout {\n    white-space: nowrap;\n}\n\n.buddy_list_tooltip_content {\n    text-align: left;\n    word-wrap: break-word;\n    /* 280px at 14px/1em */\n    max-width: 20em;\n}\n\n#change_visibility_policy_button_tooltip {\n    text-align: left;\n\n    .tooltip-privacy-icon {\n        position: relative;\n        display: inline-block;\n    }\n\n    .tooltip-privacy-icon .zulip-icon-lock {\n        margin-top: -0.15em !important;\n    }\n\n    .tooltip-privacy-icon i {\n        position: absolute;\n        top: 0.1667em;\n    }\n\n    .privacy-tooltip-stream-name {\n        margin-left: 1.25em;\n    }\n}\n\n.narrow-filter {\n    display: block;\n    position: relative;\n}\n\n.new_messages {\n    background-color: hsl(194deg 53% 79%);\n}\n\n.new_messages,\n.new_messages_fadeout {\n    transition: background-color 3s ease-in-out;\n}\n\n.messagebox-content .slow-send-spinner {\n    display: block;\n    font-size: 0.8571em; /* 12px at 14px/em */\n    text-align: right;\n    opacity: 0.8;\n    color: var(--color-text-default);\n    animation: rotate 1s infinite linear;\n}\n\n.star {\n    &:hover {\n        cursor: pointer;\n    }\n}\n\n.copy-paste-text {\n    /* Hide the text that we want copy paste to capture */\n    position: absolute;\n    text-indent: -99999px;\n    float: left;\n    width: 0;\n}\n\n@keyframes rotate {\n    from {\n        transform: rotate(0deg);\n    }\n\n    to {\n        transform: rotate(359deg);\n    }\n}\n\n@keyframes fadeInMessage {\n    0% {\n        opacity: 0;\n    }\n\n    100% {\n        opacity: 1;\n    }\n}\n\n@keyframes fadeInEditNotice {\n    0% {\n        transform: translateX(-10px);\n    }\n\n    100% {\n        transform: translateX(0);\n    }\n}\n\n.selected_message {\n    .messagebox-content {\n        /* We add an outline and shift it inside the message so that without\n           any vertical padding changes, we can have the outline surrounding\n           the message without overflowing the boundary of the message in any case. */\n        outline: 1px solid var(--color-selected-message-outline);\n        border-radius: 5px;\n        outline-offset: -1px;\n    }\n}\n\n.selected_msg_for_touchscreen {\n    @media (hover: none) {\n        .message_reactions .reaction_button {\n            visibility: visible;\n            pointer-events: all;\n        }\n    }\n}\n\n/* Make the action icon on the message row\n   always visible while the popover is open */\n.has_actions_popover .actions_hover {\n    visibility: visible !important;\n    pointer-events: all !important;\n    opacity: 1 !important;\n\n    & i:focus {\n        /* Avoid displaying a focus outline outside the popover on the \\vdots\n           icon when opened via the mouse. */\n        outline: 0 !important;\n    }\n}\n\n.has_actions_popover .info {\n    opacity: 1;\n    visibility: visible;\n}\n\n.small {\n    font-size: 80%;\n}\n\n.tiny {\n    font-size: 60%;\n}\n\ndiv.message-list {\n    border-collapse: separate;\n    margin-left: auto;\n    display: none;\n    width: 100%;\n}\n\ndiv.focused-message-list {\n    display: block;\n}\n\n/* In conversation view, always show the recipient bar action buttons */\ndiv.focused-message-list.is-conversation-view .recipient_row {\n    & .recipient_bar_controls {\n        opacity: 1;\n        transition: opacity 0.15s ease-in;\n    }\n}\n\n.rtl {\n    direction: rtl;\n}\n\n.topic_edit {\n    display: none;\n    flex-grow: 1;\n\n    .alert {\n        display: inline-block;\n        margin: 0;\n        padding: 0 10px;\n        line-height: 17px;\n    }\n}\n\n.topic_edit_form {\n    display: flex;\n    align-items: center;\n    gap: 5px;\n    margin: 0;\n    padding-right: 5px;\n}\n\n.inline_topic_edit {\n    flex: 1;\n    /* Set the max width of the inline topic edit input to the realm\'s\n       max_topic_length (60 chars) + 5 chars extra for some cushion. */\n    max-width: 65ch;\n    line-height: 1.2142em;\n    padding: 0 5px;\n    color: hsl(0deg 0% 33%);\n    border-radius: 4px;\n    border: 1px solid hsl(0deg 0% 80%);\n\n    transition:\n        border-color linear 0.2s,\n        box-shadow linear 0.2s;\n\n    &:focus {\n        border-color: hsl(206deg 80% 62% / 80%);\n        outline: 0;\n        box-shadow:\n            inset 0 1px 1px hsl(0deg 0% 0% / 7.5%),\n            0 0 8px hsl(206deg 80% 62% / 60%);\n    }\n}\n\n.topic_edit_save {\n    border-color: light-dark(hsla(0deg 0% 0% / 10%), hsla(0deg 0% 0% / 60%));\n    border-width: 1px;\n    border-style: solid;\n    background-clip: padding-box;\n}\n\n.information-settings .user-profile-picture,\n.user_sidebar_entry.with_avatar .user-profile-picture,\n.inline_profile_picture {\n    display: inline-block;\n    /* Don\'t inherit the line-height from message-avatar;\n       this preserves the dimensions and rounded corners\n       on the image itself. */\n    line-height: 1;\n    vertical-align: top;\n    border-radius: 4px;\n    overflow: hidden;\n\n    &.guest-avatar::after {\n        outline: 2px solid hsl(0deg 0% 100%);\n    }\n}\n\n.inline_profile_picture {\n    width: var(--message-box-avatar-width);\n    height: var(--message-box-avatar-height);\n}\n\n.information-settings .user-profile-picture,\n.user_sidebar_entry.with_avatar .user-profile-picture {\n    width: var(--right-sidebar-avatar-width);\n    height: var(--right-sidebar-avatar-height);\n    margin-right: var(--right-sidebar-avatar-right-margin);\n}\n\n.home-error-bar {\n    margin-top: 5px;\n    display: none;\n\n    .alert {\n        margin-bottom: auto;\n    }\n}\n\n.streamname {\n    font-weight: bold;\n}\n\n.top-navbar-container {\n    /* Calculate right margin so that title and description\n       elements can truncate and not collide with or run underneath\n       with the search section. */\n    margin-right: calc(\n        var(--search-box-width) + var(--navbar-content-righthand-offset)\n    );\n    overflow: hidden;\n    text-overflow: ellipsis;\n}\n\n.top-navbar-container-allow-description-extension {\n    overflow: visible;\n}\n\n#streamlist-toggle {\n    display: none;\n    position: absolute;\n    top: 0;\n    left: 0;\n    text-align: center;\n}\n\n.hide-streamlist-toggle-visibility,\n.hide-navbar-buttons-visibility {\n    visibility: hidden;\n}\n\n#header-container .left-sidebar-toggle-button {\n    text-decoration: none;\n    color: var(--color-navbar-icon);\n    display: flex;\n    position: relative;\n    align-items: center;\n    justify-content: center;\n    width: var(--header-height);\n    height: var(--header-height);\n\n    &:hover {\n        background-color: var(--color-header-button-hover);\n\n        .left-sidebar-toggle-unreadcount {\n            border-color: var(--color-header-button-hover-no-alpha);\n        }\n    }\n\n    &:active {\n        background-color: var(--color-header-button-focus);\n    }\n\n    &:focus {\n        outline: 0;\n    }\n\n    &:focus-visible {\n        outline: none;\n        background-color: var(--color-header-button-focus);\n    }\n\n    &:active,\n    &:focus-visible {\n        .left-sidebar-toggle-unreadcount {\n            border-color: var(--color-header-button-focus-no-alpha);\n        }\n    }\n}\n\n.left-sidebar-toggle-unreadcount {\n    position: absolute;\n    display: none;\n    /* 6px at 16px/1em */\n    height: 0.375em;\n    width: 0.375em;\n    background-color: var(--color-navbar-icon);\n\n    /* 2px at 16px/1em */\n    border: 0.125em solid var(--color-background-navbar);\n    /* 6px at 16px/1em */\n    border-radius: 0.375em;\n    padding: 0;\n\n    /* At 16px/1em, the toggle icon is 20px on a side, which is\n       half the width of its container (40px on a side). To\n       place the 10px-wide unread counter correctly, then, we\n       set it to 25% of the right of the container, or 10px,\n       and likewise 25% down from the top of the container,\n       also 10px. */\n\n    top: 25%;\n    right: 25%;\n}\n\nnav {\n    .column-left {\n        text-align: left;\n        display: flex;\n        justify-content: left;\n        gap: 4px;\n\n        .brand {\n            display: flex;\n            align-items: center;\n        }\n\n        .nav-logo {\n            display: inline-block;\n            height: 1.25em; /* 20px at 16px em */\n            max-width: var(--realm-logo-max-width);\n\n            @media (height < $short_navbar_cutoff_height) {\n                height: 0.9375em; /* 15px at 16px em */\n            }\n        }\n\n        .left-sidebar-toggle-button .left-sidebar-toggle-unreadcount {\n            /* The toggle icon is half the width of its container\n            and is at the center of the container.\n            So, the left width starts from left 25% of the container\n            and ends till 75% of the container\'s width.\n            Similarly, vertically, the dot is starts at the top 25% of\n            the container\'s height and ends at 75% of the total height\n\n            So, the top right corner of the icon is at 25% from top and\n            75% from the right. This is the location where we place the\n            unread indicator dot. */\n            top: 25%;\n            right: 25%;\n        }\n    }\n\n    & a {\n        &.no-style:hover {\n            text-decoration: none;\n            cursor: pointer;\n        }\n\n        .no-style {\n            text-decoration: none;\n        }\n    }\n}\n\n#bottom_whitespace {\n    display: block;\n    height: var(--max-unmaximized-compose-height);\n}\n\n.operator_value {\n    font-family: "Source Code Pro", monospace;\n    color: hsl(353deg 70% 65%);\n}\n\n.operator {\n    font-family: "Source Code Pro", monospace;\n}\n\n#loading_older_messages_indicator,\n#loading_newer_messages_indicator {\n    margin: 10px;\n}\n\n#loading_older_messages_indicator_box_container,\n#loading_newer_messages_indicator_box_container {\n    position: absolute;\n    left: 50%;\n}\n\n#loading_older_messages_indicator_box,\n#loading_newer_messages_indicator_box {\n    position: relative;\n    left: -50%;\n    top: -43px;\n    z-index: 1;\n    border-radius: 6px;\n}\n\n#page_loading_indicator {\n    margin: 10px auto;\n}\n\n#page_loading_indicator_box_container {\n    position: absolute;\n    left: 50%;\n}\n\n#page_loading_indicator_box {\n    position: relative;\n    left: -50%;\n    top: -43px;\n    z-index: 1;\n    border-radius: 6px;\n}\n\n#create_stream_subscribers {\n    margin-top: 10px;\n\n    .checkbox {\n        display: block;\n\n        & input[type="checkbox"] {\n            margin: 5px 0;\n            float: none;\n        }\n    }\n}\n\n.sub_button_row {\n    text-align: center;\n}\n\ndiv.topic_edit_spinner {\n    display: inline-block;\n    width: 18px;\n    height: 18px;\n    margin-top: -1px;\n    padding: 2px;\n    vertical-align: middle;\n}\n\ndiv.toggle_resolve_topic_spinner {\n    margin-top: -12px;\n    padding-left: 9px;\n}\n\ndiv.topic_edit_spinner .loading_indicator_spinner,\ndiv.toggle_resolve_topic_spinner .loading_indicator_spinner {\n    width: 14px;\n    height: 14px;\n\n    & path {\n        fill: var(--color-recipient-bar-controls-spinner);\n    }\n}\n\n.custom-time-input-value,\n#invite-user-form {\n    margin: 0;\n}\n\n.invite-user-select {\n    vertical-align: middle;\n}\n\n#multiuse_invite_link {\n    width: 370px;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n    display: inline-block;\n    overflow: hidden;\n    vertical-align: bottom;\n}\n\n.add-user-group-container,\n.add_streams_container {\n    display: inline-flex;\n    align-items: center;\n    width: 100%;\n}\n\n.custom-time-input-value {\n    width: 5ch;\n    margin-right: 15px;\n\n    padding: 4px 6px;\n    color: hsl(0deg 0% 33%);\n    border-radius: 4px;\n    border: 1px solid hsl(0deg 0% 80%);\n    box-shadow: inset 0 1px 1px hsl(0deg 0% 0% / 7.5%);\n    transition:\n        border-color linear 0.2s,\n        box-shadow linear 0.2s;\n\n    &:focus {\n        border-color: hsl(206deg 80% 62% / 80%);\n        outline: 0;\n        box-shadow:\n            inset 0 1px 1px hsl(0deg 0% 0% / 7.5%),\n            0 0 8px hsl(206deg 80% 62% / 60%);\n    }\n}\n\n.custom-time-input-unit {\n    width: auto;\n}\n\n.empty_feed_notice {\n    max-width: 42.8571em;\n    margin: 0 auto;\n    padding: 3em 1em;\n    text-align: center;\n}\n\n.empty-feed-notice-title {\n    font-size: 1.5em;\n    font-weight: 400;\n    line-height: inherit;\n    word-wrap: break-word;\n}\n\n.empty-feed-notice-description {\n    font-size: 1.1em;\n\n    .search-query-word {\n        word-wrap: break-word;\n    }\n}\n\n.message-fade,\n.user_sidebar_entry.user-fade {\n    opacity: 0.4;\n}\n\n.emoji {\n    height: 25px;\n    width: 25px;\n    /* Maintain `vertical-align` for inline-block styles in messages: */\n    vertical-align: middle;\n    /* But, for all others, use flexbox and its align-self property.\n      What is excellent about this is that flexbox will ignore the\n      `vertical-align` value, while inline-block contexts will ignore\n      the `align-self` property: */\n    align-self: center;\n}\n\n.status-emoji {\n    /* 16px at 14px/1em */\n    height: 1.1429em;\n    width: 1.1429em;\n    /* We are setting minimum width here because when the user\'s name is very long,\n    emoji\'s width decreases and causes it to break. */\n    min-width: 1.1429em;\n    /* In most contexts, status emoji appear immediately after a name\n      field with no margin. Position the status emoji with 3px of left\n      margin to space it from the name, and set no right margin so\n      that any components to the right appear equally distant as they\n      would be from a name. */\n    margin-left: 3px;\n    margin-right: 0;\n}\n\n/* FIXME: Combine this rule with the one in portico.css somehow? */\n#pw_strength {\n    width: 100%;\n    height: 10px;\n    margin-bottom: 0;\n}\n\n.sub-unsub-message {\n    padding-bottom: 10px;\n    text-align: center;\n}\n\n.sub-unsub-message span {\n    font-size: 1em;\n    display: block;\n    padding: 4px;\n    overflow: hidden;\n}\n\n.sub-unsub-message .stream-status {\n    opacity: 0.6;\n\n    & i {\n        font-size: 0.7143em; /* 10px at 14px / em */\n        /* TODO: Don\'t use relative positioning here. */\n        position: relative;\n        top: 0.1em; /* 1px at 10px / em */\n        margin-left: 0.2em; /* 2px at 10px / em */\n    }\n\n    .zulip-icon.zulip-icon-lock {\n        font-size: 0.8571em; /* 12px at 14px / em */\n        top: 0.0833em; /* 1px at 12px / em */\n        margin-left: 0.1667em; /* 2px at 12px / em */\n    }\n}\n\n.sub-unsub-message span::before,\n.sub-unsub-message span::after,\n.date_row span::before,\n.date_row span::after {\n    display: inline-block;\n    position: relative;\n    content: " ";\n    vertical-align: middle;\n    height: 0;\n    opacity: 0.15;\n    border-bottom: 1px solid hsl(0deg 0% 0%);\n}\n\n.sub-unsub-message span::before,\n.sub-unsub-message span::after {\n    width: 50%;\n}\n\n.date_row span::before {\n    width: 100%;\n}\n\n.date_row span::after {\n    width: 6px;\n    left: 0.25em;\n    /* Align date with message time and recipient bar date. */\n    margin-right: -1px;\n}\n\n.sub-unsub-message span::before,\n.date_row span::before {\n    right: 0.25em;\n    margin-left: -50%;\n}\n\n.sub-unsub-message span::after {\n    left: 0.25em;\n    margin-right: -50%;\n}\n\n.screen {\n    position: absolute;\n    left: 0;\n    top: 0;\n    background-color: hsl(0deg 0% 0%);\n    z-index: 20000;\n}\n\n.deactivated_user .deactivated-user-icon {\n    color: inherit;\n    margin-left: 2px;\n    font-size: 0.9em;\n}\n\n.no-drag {\n    -webkit-user-drag: none;\n    user-select: none;\n}\n\n.flatpickr-calendar {\n    /* Hide the up and down arrows in the Flatpickr datepicker year */\n    .flatpickr-months .numInputWrapper span {\n        display: none;\n    }\n\n    .flatpickr-time-separator {\n        position: relative;\n        left: 5px;\n    }\n\n    .flatpickr-time input {\n        margin: 0 5px;\n        min-height: 30px;\n    }\n\n    .flatpickr-confirm {\n        color: hsl(0deg 0% 100%);\n        background-color: hsl(213deg 90% 65%);\n        font-size: var(--flatpickr-confirm-button-font-size);\n        font-weight: 600;\n    }\n\n    @media (width < $md_min) {\n        /* Center align flatpickr on mobile\n         * devices so that it doesn\'t go out of\n         * the viewport. */\n        left: 0 !important;\n        right: 0 !important;\n        margin: auto;\n\n        &::after,\n        &::before {\n            border-top-width: 0 !important;\n        }\n    }\n}\n\n#about-zulip {\n    .exit {\n        font-size: 1.5rem;\n        font-weight: 600;\n        background-color: transparent;\n        border: none;\n        position: absolute;\n        right: 8px;\n        z-index: 1;\n        color: hsl(0deg 0% 67%);\n    }\n\n    .overlay-content {\n        width: 440px;\n        border-radius: 4px;\n    }\n\n    .zulip-version-info,\n    .zulip-merge-base-info {\n        display: flex;\n        align-items: center;\n        gap: 5px;\n    }\n\n    .about-zulip-logo {\n        text-align: center;\n        margin: 30px;\n    }\n\n    .about-zulip-logo img {\n        height: 40px;\n    }\n\n    .overlay-body {\n        max-height: 60vh;\n        padding: 15px;\n    }\n}\n\n@media (width < $xl_min) or (height < $short_navbar_cutoff_height) {\n    .spectator-view {\n        #navbar-middle {\n            /* = (width of button, square with header) * 3 (number of buttons) + 10px extra margin. */\n            margin-right: calc(var(--header-height) * 3 + 10px);\n        }\n\n        #help-menu,\n        #gear-menu {\n            position: relative;\n            right: var(--header-height);\n        }\n\n        #top_navbar .column-right .spectator_login_buttons {\n            display: none;\n        }\n    }\n\n    .header-main .column-right {\n        /* For a diminutive right column in the navbar,\n           allow the width to be that of the flexing\n           button elements. */\n        width: auto;\n    }\n}\n\n%hide-right-sidebar {\n    .column-right {\n        display: none;\n\n        &.expanded {\n            /* In the extended state, we open the sidebar\n               to its maximum possible size (otherwise, it\n               would be unnecessarily too narrow). */\n            --right-sidebar-width: var(--right-sidebar-max-width);\n            display: block;\n            position: absolute;\n            float: none;\n            right: 15px;\n            top: 0;\n\n            .simplebar-track.simplebar-vertical {\n                right: 0;\n            }\n\n            .right-sidebar {\n                box-shadow: 0 -2px 3px 0 hsl(0deg 0% 0% / 10%);\n                border-left: 1px solid var(--color-border-sidebar);\n                height: 100%;\n                width: var(--right-sidebar-width);\n                right: 0;\n                background-color: var(--color-background);\n            }\n        }\n    }\n}\n\n.hide-right-sidebar {\n    .app-main {\n        @extend %hide-right-sidebar;\n    }\n\n    #navbar-middle {\n        margin-right: var(--right-column-collapsed-sidebar-width);\n    }\n\n    #compose-content,\n    .app-main .column-middle {\n        margin-right: 7px;\n    }\n}\n\n.hide-right-sidebar-by-visibility .app-main .column-right {\n    visibility: hidden;\n}\n\n.left-sidebar-toggle-button .zulip-icon-panel-left {\n    display: none;\n}\n\n.column-middle.expanded {\n    .left-sidebar-toggle-button .zulip-icon-panel-left {\n        display: none;\n    }\n\n    .left-sidebar-toggle-button .zulip-icon-panel-left-dashed {\n        display: block;\n    }\n}\n\n%hide-left-sidebar {\n    .left-sidebar-toggle-button .zulip-icon-panel-left {\n        display: block;\n    }\n\n    .left-sidebar-toggle-button .zulip-icon-panel-left-dashed {\n        display: none;\n    }\n\n    .column-left {\n        display: none;\n\n        &.expanded {\n            /* In the extended state, we open the sidebar\n               to its maximum possible size (otherwise, it\n               would be unnecessarily too narrow). */\n            --left-sidebar-width: var(--left-sidebar-max-width);\n            display: block;\n            position: absolute;\n            float: none;\n            left: 0;\n            top: 0;\n\n            .left-sidebar {\n                background-color: var(--color-background);\n                box-shadow: 0 2px 3px 0 hsl(0deg 0% 0% / 10%);\n                border-right: 1px solid var(--color-border-sidebar);\n                height: 100%;\n                padding-left: 10px;\n                width: var(--left-sidebar-width);\n            }\n        }\n    }\n}\n\n.hide-left-sidebar {\n    .app-main {\n        @extend %hide-left-sidebar;\n    }\n\n    #compose-content,\n    .app-main .column-middle {\n        margin-left: 7px;\n    }\n\n    @container header-container (width > $cq_md_min) {\n        #navbar-middle {\n            margin-left: var(--middle-column-left-margin-fluid-layout);\n        }\n    }\n\n    @container header-container (width < $cq_xl_min) {\n        #top_navbar .column-left {\n            width: auto;\n        }\n    }\n\n    @container header-container (width < $cq_md_min) {\n        #navbar-middle {\n            margin-left: 0;\n        }\n    }\n\n    @container app (width < $cq_xl_min) {\n        #compose-content,\n        .app-main .column-middle {\n            margin-left: 7px;\n        }\n    }\n}\n\n/* Media-query fallback for the cinched-up logo presentation. */\n@media (width > $md_min) {\n    .without-container-query-support {\n        &.hide-left-sidebar {\n            #navbar-middle {\n                margin-left: var(--middle-column-left-margin-fluid-layout);\n            }\n        }\n    }\n}\n\nbody:not(.hide-left-sidebar) {\n    /* User can clearly see the unread count in the left sidebar. So,\n       we don\'t need an indicator here as it will only serve as a disctraction. */\n    #header-container .column-left .left-sidebar-toggle-unreadcount {\n        display: none !important;\n    }\n}\n\nbody:not(.spectator-view) {\n    /* The large Log In button for spectators makes this rule\n       inappropriate for that view. */\n    @container header-container (width < $cq_xl_min) {\n        #navbar-middle {\n            /* = (width of button, square with header) * 4 (number of buttons) + 3px extra margin. */\n            margin-right: var(--right-column-collapsed-sidebar-width);\n        }\n    }\n}\n\n/* We have some regrettable but temporarily necessary code duplication\n   in the queries that follow.\n\n   In browsers that support spec-aligned, em-aware container queries,\n   we query on the app-main container. That enables breakpoints that\n   look best at a chose base font size.\n\n   However, in browsers that lag the spec, we fall back to the original\n   media queries. The layout will not look as good as it could, but\n   essential scrolling behavior will be maintained. */\n\n@container app (width < $cq_xl_min) {\n    .app-main {\n        @extend %hide-right-sidebar;\n\n        .column-middle {\n            margin-right: 7px;\n        }\n    }\n\n    #typing_notifications,\n    #scheduled_message_indicator,\n    #compose-content {\n        margin-right: 7px;\n    }\n}\n\n@container header-container (width < $cq_md_min) {\n    .header-main .column-left {\n        display: none;\n    }\n\n    #navbar-middle {\n        margin-left: 0;\n    }\n\n    #streamlist-toggle {\n        display: block;\n    }\n\n    .top-navbar-container {\n        /* The --header-height variable is used to make\n        the squared toggle area, so we offset it\n        accordingly. */\n        margin-left: var(--header-height);\n    }\n}\n\n@container app (width < $cq_md_min) {\n    .app-main {\n        @extend %hide-left-sidebar;\n\n        .column-middle {\n            margin-left: 7px;\n            margin-right: 7px;\n        }\n\n        .column-middle .column-middle-inner {\n            margin-left: 0;\n            margin-right: 0;\n        }\n    }\n\n    #typing_notifications,\n    #scheduled_message_indicator,\n    #compose-content {\n        margin-left: 7px;\n    }\n}\n\n@container app (width <= $cq_ml_min) {\n    .column-right.expanded,\n    .column-left.expanded {\n        width: 100vw;\n        max-width: 100%;\n    }\n\n    .app-main .column-right.expanded .right-sidebar,\n    .app-main .column-left.expanded .left-sidebar {\n        width: 100vw;\n        max-width: 100%;\n    }\n}\n\n@container header-container (width <= $cq_sm_min) {\n    .narrow_description {\n        display: none;\n    }\n}\n\n/* Begin fallback media queries. */\n@media (width < $xl_min) {\n    .without-container-query-support {\n        .app-main {\n            @extend %hide-right-sidebar;\n\n            .column-middle {\n                margin-right: 7px;\n            }\n        }\n\n        #navbar-middle {\n            /* = (width of button, square with header) * 4 (number of buttons) + 3px extra margin. */\n            margin-right: calc(var(--header-height) * 4 + 3px);\n        }\n\n        #typing_notifications,\n        #scheduled_message_indicator,\n        #compose-content {\n            margin-right: 7px;\n        }\n\n        .hide-left-sidebar {\n            #compose-content,\n            .app-main .column-middle {\n                margin-left: 7px;\n            }\n\n            #top_navbar .column-left {\n                width: auto;\n            }\n        }\n    }\n}\n\n@media (width < $md_min) {\n    .without-container-query-support {\n        .app-main {\n            @extend %hide-left-sidebar;\n\n            .column-middle {\n                margin-left: 7px;\n                margin-right: 7px;\n            }\n\n            .column-middle .column-middle-inner {\n                margin-left: 0;\n                margin-right: 0;\n            }\n        }\n\n        .header-main .column-left {\n            display: none;\n        }\n\n        #navbar-middle {\n            margin-left: 0;\n        }\n\n        #streamlist-toggle {\n            display: block;\n        }\n\n        .top-navbar-container {\n            margin-left: 40px;\n        }\n\n        #feedback_container {\n            width: calc(90% - 30px);\n            left: 5%;\n            top: 5%;\n        }\n\n        #typing_notifications,\n        #scheduled_message_indicator,\n        #compose-content {\n            margin-left: 7px;\n        }\n    }\n}\n\n@media (width <= $ml_min) {\n    .without-container-query-support {\n        .column-right.expanded,\n        .column-left.expanded {\n            width: 100vw;\n            max-width: 100%;\n        }\n\n        .app-main .column-right.expanded .right-sidebar,\n        .app-main .column-left.expanded .left-sidebar {\n            width: 100vw;\n            max-width: 100%;\n        }\n    }\n}\n\n@media (width <= $sm_min) {\n    .without-container-query-support {\n        .narrow_description {\n            display: none;\n        }\n    }\n}\n\n/* End fallback media queries. */\n\n/* Begin viewport state queries. */\n\n/* We sometimes need the state of the viewport in JavaScript;\n   by setting values on `content:`, we can query instead for\n   those, independent of whether it\'s a container or media query\n   responsible for layout. See for example `sidebar_ui.ts`.\n\n   These queries for greater than or equal to should be ordered\n   smallest to largest. */\n\n/* Adjustments for smaller viewports are critical\n   regardless of info-density settings, so we\n   don\'t include a container-query check here. */\n@media (width < $md_min) {\n    .app-main::after {\n        content: "lt_md_min";\n    }\n}\n\n@container app (width >= $cq_md_min) {\n    .app-main::after {\n        content: "gte_md_min";\n    }\n}\n\n@media (width >= $md_min) {\n    .without-container-query-support {\n        .app-main::after {\n            content: "gte_md_min";\n        }\n    }\n}\n\n@container app (width >= $cq_xl_min) {\n    .app-main::after {\n        content: "gte_md_min gte_xl_min";\n    }\n}\n\n@media (width >= $xl_min) {\n    .without-container-query-support {\n        .app-main::after {\n            content: "gte_md_min gte_xl_min";\n        }\n    }\n}\n\n/* End viewport state queries. */\n\n@media (height < $short_navbar_cutoff_height) {\n    .app-main .column-right.expanded .right-sidebar,\n    .app-main .column-left.expanded .left-sidebar {\n        margin-top: var(--navbar-fixed-height);\n        /* For very short screen sizes, skip the relatively large top padding. */\n        padding-top: 0;\n    }\n\n    /* TODO: Properly and accurately align the\n       topmost headers on the left and right\n       sidebar. */\n    .app-main .column-right.expanded .right-sidebar-items {\n        margin-top: 10px;\n    }\n\n    .app-main .column-left.expanded .left-sidebar-navigation-area {\n        margin-top: 10px;\n    }\n\n    /* Usually the styling is applied directly to the icon, but here\n    the icon is `position: static`, so we can\'t. */\n    .search_closed {\n        top: 5px;\n    }\n\n    #streamlist-toggle,\n    #message_view_header,\n    #searchbox,\n    .header {\n        line-height: var(--header-height);\n        height: var(--header-height);\n    }\n\n    .spectator_narrow_login_button {\n        height: var(--header-height) !important;\n    }\n\n    .left-sidebar-toggle-button {\n        height: var(--header-height);\n    }\n\n    nav\n        .column-left\n        .left-sidebar-toggle-button\n        .left-sidebar-toggle-unreadcount {\n        top: 5px;\n        left: 16px;\n    }\n\n    .left-sidebar-toggle-unreadcount {\n        /* Adjust in response to shorter navbar. */\n        top: 5px;\n        right: 4px;\n    }\n\n    #top_navbar .column-right #personal-menu .header-button-avatar {\n        width: 1.25em; /* 20px at 16px em */\n        height: 1.25em; /* 20px at 16px em */\n    }\n}\n\n/* As these adjustments are properly the province of\n   the viewport, we do not present these mm_min queries\n   in a corresponding container query block. */\n@media (width < $mm_min) {\n    html {\n        overflow-x: hidden;\n    }\n\n    /* We don\'t want user to experience Zulip below this width since\n       we don\'t develop features for below this width. */\n    body,\n    html,\n    .app-main,\n    .header-main {\n        min-width: 320px;\n    }\n\n    #compose #compose-content {\n        margin-right: 5px;\n        margin-left: 5px;\n    }\n}\n\n#scroll-to-bottom-button-container {\n    display: block;\n    position: absolute;\n    bottom: 41px;\n    right: 0;\n    visibility: hidden;\n    opacity: 0;\n    transition:\n        visibility 500ms,\n        opacity 500ms ease-in-out;\n\n    &.show {\n        visibility: visible;\n        opacity: 1;\n    }\n\n    #scroll-to-bottom-button-clickable-area {\n        width: 3.75em; /* 60px at 16px em */\n        height: 3.75em; /* 60px at 16px em */\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        cursor: pointer;\n\n        &:hover #scroll-to-bottom-button {\n            background: hsl(240deg 96% 68%);\n        }\n\n        #scroll-to-bottom-button {\n            text-align: center;\n            width: 2.5em; /* 40px at 16px em */\n            height: 2.5em; /* 40px at 16px em */\n            background: hsl(240deg 96% 68% / 50%);\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n\n            & .scroll-to-bottom-icon {\n                color: hsl(0deg 0% 100%);\n                margin: 0 auto;\n                font-size: 1.3125em; /* 21px at 16px em */\n            }\n        }\n    }\n}\n\n.spectator_login_for_image_button {\n    max-width: 250px;\n    height: 50px;\n\n    :hover {\n        text-decoration: none;\n    }\n\n    .login_button {\n        padding: 5px;\n        margin-top: 5px;\n\n        .fa {\n            top: 1px;\n        }\n    }\n}\n\n.simplebar-content-wrapper {\n    /* `simplebar-content-wrapper` has `tabindex=-1` set, which makes sure\n       that it does not get focus when navigating via a keyboard.\n\n       But in a few situations, we programmatically focus this\n       element, and in this case, we don\'t want to see the outline. */\n    outline: none;\n\n    /* This prevents the popover from closing once the top/bottom is reached */\n    overscroll-behavior: contain;\n}\n\n.popover-filter-input-wrapper {\n    display: flex;\n\n    .popover-filter-input {\n        background: var(--color-background-widget-input);\n        color: var(--color-text-dropdown-input);\n        width: 100%;\n        margin: 4px 4px 2px;\n\n        &:focus {\n            background: hsl(0deg 0% 100%);\n            border: 1px solid hsl(229.09deg 21.57% 10% / 80%);\n            box-shadow: 0 0 6px hsl(228deg 9.8% 20% / 30%);\n        }\n    }\n}\n\n.dropdown-list-container {\n    .dropdown-list-wrapper {\n        /* Sync with `max-height` in dropdown_widget. */\n        max-height: 210px;\n        /* 200px/14px */\n        min-width: 14.285em;\n\n        .dropdown-list {\n            list-style: none;\n            margin: 0;\n        }\n    }\n\n    .no-dropdown-items {\n        color: hsl(0deg 0% 60%);\n        display: none;\n        padding: 3px 10px 3px 8px;\n        font-weight: 400;\n        line-height: 20px;\n        white-space: normal;\n    }\n}\n\n.dropdown-list-container .list-item {\n    color: var(--color-dropdown-item);\n\n    &:focus {\n        background-color: var(--background-color-active-dropdown-item);\n        outline: none;\n    }\n}\n\n.dropdown-list-container .dropdown-list .dropdown-list-item-common-styles {\n    position: relative;\n    display: flex;\n    align-items: center;\n    color: var(--color-dropdown-item);\n    padding: 3px 10px 3px 8px;\n    font-weight: 400;\n    line-height: var(--base-line-height-unitless);\n    white-space: normal;\n\n    .stream-privacy-type-icon {\n        font-size: 0.93em;\n        /* We set only the width so that flexbox\n           can do its work to properly center,\n           regardless of the height. */\n        width: 0.93em;\n        padding-right: 5px;\n        /* Override the [data-tippy-root]\n           style in `tooltips.css`. */\n        top: 0;\n    }\n\n    .dropdown-list-delete {\n        position: absolute;\n        top: 0;\n        right: 5px;\n        visibility: hidden;\n    }\n\n    &:focus,\n    &:hover {\n        color: var(--color-dropdown-item);\n        text-decoration: none;\n        background-color: var(--background-color-active-dropdown-item);\n        outline: none;\n\n        .dropdown-list-delete {\n            visibility: visible;\n        }\n    }\n}\n\n.dropdown-list-item-common-styles .dropdown-list-bold-selected {\n    font-weight: 700;\n}\n\n#scheduled_messages_overlay .error-icon-message-recipient {\n    width: 15px;\n    height: 100%;\n    display: flex;\n    align-items: center;\n    justify-content: flex-end;\n    flex-grow: 1;\n    color: var(--color-failed-message-send-icon);\n\n    .zulip-icon {\n        padding: 5px;\n    }\n}\n\n.emoji-popover-tab-item {\n    .zulip-icon-star {\n        position: relative;\n        top: 2px;\n    }\n}\n\n.header-main .column-right {\n    display: flex;\n    justify-content: flex-end;\n    align-items: center;\n\n    & a:focus {\n        filter: none;\n        outline: 0;\n    }\n}\n\n.header-button {\n    width: var(--header-height);\n    height: var(--header-height);\n    display: flex;\n    justify-content: center;\n    align-items: center;\n\n    &:hover,\n    &:focus {\n        text-decoration: none;\n    }\n\n    &:hover {\n        background-color: var(--color-header-button-hover);\n    }\n\n    &:active {\n        background-color: var(--color-header-button-focus);\n    }\n\n    &:focus-visible {\n        outline: none;\n        background-color: var(--color-header-button-focus);\n    }\n\n    .zulip-icon {\n        color: var(--color-navbar-icon);\n    }\n\n    .zulip-icon-gear {\n        font-size: 1.125em; /* 18px at 16px em */\n    }\n\n    .zulip-icon-help-bigger,\n    .zulip-icon-user-list {\n        font-size: 1.25em; /* 20px at 16px em */\n    }\n\n    .zulip-icon-help {\n        position: relative;\n        top: 0.5px;\n        right: -0.5px;\n    }\n}\n\n.left-sidebar-toggle-button {\n    .zulip-icon-panel-left,\n    .zulip-icon-panel-left-dashed {\n        font-size: 1.25em; /* 20px at 16px em */\n    }\n}\n\n#personal-menu {\n    .header-button-avatar {\n        width: 1.5em; /* 24px at 16px em */\n        height: 1.5em; /* 24px at 16px em */\n        background-size: cover;\n        border-radius: 4px;\n        background-color: var(--color-background-image-loader);\n        border: 1px solid var(--color-border-personal-menu-avatar);\n    }\n}\n\n.empty-topic-display,\n.empty-topic-placeholder-display::placeholder {\n    font-style: italic;\n}\n\n.popover-menu-user-avatar-container.deactivated,\n.inline_profile_picture.deactivated {\n    position: relative;\n\n    > img {\n        opacity: 0.5;\n    }\n\n    .deactivated-user-icon {\n        background-color: var(--color-background);\n        color: var(--color-user-circle-deactivated);\n        padding: 2px;\n        font-size: 0.8em;\n        position: absolute;\n        border-radius: 10px;\n        bottom: -2px;\n        right: -2px;\n    }\n}\n',
            'web/templates/dropdown_list.hbs': '{{#with item}}\n    <li class="list-item" role="presentation" data-unique-id="{{unique_id}}" data-name="{{name}}" tabindex="0">\n        {{#if description}}\n        <a class="dropdown-list-item-common-styles">\n            <span class="dropdown-list-item-name">\n                {{#if bold_current_selection}}\n                    <span class="dropdown-list-bold-selected">{{name}}</span>\n                    {{#if has_delete_icon}}\n                        {{> components/icon_button custom_classes="dropdown-list-delete" intent="danger" icon="trash" aria-label=(t "Delete snippet") }}\n                    {{/if}}\n                {{else}}\n                    {{name}}\n                {{/if}}\n            </span>\n            <span class="dropdown-list-item-description line-clamp">\n                {{description}}\n            </span>\n        </a>\n        {{else}}\n        <a class="dropdown-list-item-common-styles">\n            {{#if stream}}\n                {{> inline_decorated_stream_name stream=stream show_colored_icon=true}}\n            {{else if is_direct_message}}\n                <i class="zulip-icon zulip-icon-users stream-privacy-type-icon"></i> {{name}}\n            {{else if is_setting_disabled}}\n                <span class="setting-disabled-option"><i class="setting-disabled-option-icon fa fa-ban" aria-hidden="true"></i>{{t "Disable" }}</span>\n            {{else}}\n                {{#if bold_current_selection}}\n                    <span class="dropdown-list-bold-selected">{{name}}</span>\n                {{else}}\n                    {{name}}\n                {{/if}}\n            {{/if}}\n        </a>\n        {{/if}}\n    </li>\n{{/with}}\n',
        }
